auto
overlap_kernel_2_0(const double* bra_exp, const double* ket_exp, const double* weights,
                          const double* ac_x, const double* ac_y, const double* ac_z,
                          const std::size_t cdim, const int nppairs, double* spherical) -> void
{
    const auto stride = ((cdim + 7) / 8) * 8;
    constexpr std::size_t tile = 512;

    if (g_kernel_scratch.size() < 15 * tile) g_kernel_scratch.resize(15 * tile);
    auto* s = g_kernel_scratch.data();

    for (std::size_t t0 = 0; t0 < cdim; t0 += tile)
    {
        const std::size_t w = (t0 + tile < cdim) ? tile : (cdim - t0);

        // (1) the contracted seed ladder [0]^m
#pragma omp simd
        for (std::size_t k = 0; k < w; k++) s[0 + k] = 0.0;
#pragma omp simd
        for (std::size_t k = 0; k < w; k++) s[512 + k] = 0.0;
#pragma omp simd
        for (std::size_t k = 0; k < w; k++) s[1024 + k] = 0.0;
        for (int pp = 0; pp < nppairs; pp++)
        {
            const double* be = bra_exp + static_cast<std::size_t>(pp) * cdim + t0;
            const double* ke = ket_exp + static_cast<std::size_t>(pp) * cdim + t0;
            const double* wt = weights + static_cast<std::size_t>(pp) * cdim + t0;
#pragma omp simd
            for (std::size_t k = 0; k < w; k++)
            {
                const double a = be[k];
                const double g = ke[k];
                const double ia = 0.5 / a;
                const double ig = -0.5 / g;
                double t = wt[k] * ia * ia;
                s[0 + k] += t;
                const double f = -2.0 * a * g / (a + g);
                t *= f;
                s[512 + k] += t;
                t *= f;
                s[1024 + k] += t;
            }
        }

        // (2) the single-centre MD recursion [r]^0
#pragma omp simd
        for (std::size_t k = 0; k < w; k++)
            s[1536 + k] = ac_x[t0 + k] * s[512 + k];
#pragma omp simd
        for (std::size_t k = 0; k < w; k++)
            s[2048 + k] = ac_x[t0 + k] * s[1024 + k];
#pragma omp simd
        for (std::size_t k = 0; k < w; k++)
            s[2560 + k] = ac_y[t0 + k] * s[512 + k];
#pragma omp simd
        for (std::size_t k = 0; k < w; k++)
            s[3072 + k] = ac_y[t0 + k] * s[1024 + k];
#pragma omp simd
        for (std::size_t k = 0; k < w; k++)
            s[3584 + k] = ac_z[t0 + k] * s[512 + k];
#pragma omp simd
        for (std::size_t k = 0; k < w; k++)
            s[4096 + k] = ac_z[t0 + k] * s[1024 + k];
#pragma omp simd
        for (std::size_t k = 0; k < w; k++)
            s[4608 + k] = ac_x[t0 + k] * s[2048 + k] + 1.0 * s[512 + k];
#pragma omp simd
        for (std::size_t k = 0; k < w; k++)
            s[5120 + k] = ac_x[t0 + k] * s[3072 + k];
#pragma omp simd
        for (std::size_t k = 0; k < w; k++)
            s[5632 + k] = ac_x[t0 + k] * s[4096 + k];
#pragma omp simd
        for (std::size_t k = 0; k < w; k++)
            s[6144 + k] = ac_y[t0 + k] * s[3072 + k] + 1.0 * s[512 + k];
#pragma omp simd
        for (std::size_t k = 0; k < w; k++)
            s[6656 + k] = ac_y[t0 + k] * s[4096 + k];
#pragma omp simd
        for (std::size_t k = 0; k < w; k++)
            s[7168 + k] = ac_z[t0 + k] * s[4096 + k] + 1.0 * s[512 + k];

        // (3) the Cartesian-to-spherical assembly
        {
            double* out = spherical + 0 * stride + t0;
#pragma omp simd
            for (std::size_t k = 0; k < w; k++) out[k] = 1.7320508075688772 * s[5120 + k];
        }
        {
            double* out = spherical + 1 * stride + t0;
#pragma omp simd
            for (std::size_t k = 0; k < w; k++) out[k] = 1.7320508075688772 * s[6656 + k];
        }
        {
            double* out = spherical + 2 * stride + t0;
#pragma omp simd
            for (std::size_t k = 0; k < w; k++) out[k] = -0.5 * s[4608 + k] + -0.5 * s[6144 + k] + 1.0 * s[7168 + k];
        }
        {
            double* out = spherical + 3 * stride + t0;
#pragma omp simd
            for (std::size_t k = 0; k < w; k++) out[k] = 1.7320508075688772 * s[5632 + k];
        }
        {
            double* out = spherical + 4 * stride + t0;
#pragma omp simd
            for (std::size_t k = 0; k < w; k++) out[k] = 0.8660254037844386 * s[4608 + k] + -0.8660254037844386 * s[6144 + k];
        }
    }
}

