                const double a = be[k];
                const double g = ke[k];
                const double ia = 0.5 / a;
                const double ig = -0.5 / g;
                double t = wt[k] * ia * ia * ia * ia;
                s[0 + k] += t;
                const double f = -2.0 * a * g / (a + g);
